<?php declare(strict_types=1);require_once dirname(__DIR__).'/includes/cms.php';$pdo=obtenerConexion();$id=cmsId($_GET['id']??$_POST['id']??0);$f=['nombre'=>'','sku'=>'','descripcion_corta'=>'','descripcion'=>'','precio'=>'0.00','stock'=>0,'stock_minimo'=>0,'disponible'=>1,'activo'=>1,'imagen_principal'=>'','categoria_id'=>null];if($id){$q=$pdo->prepare('SELECT * FROM productos WHERE id=:id AND eliminado_at IS NULL');$q->execute(['id'=>$id]);$f=$q->fetch()?:$f;if(empty($f['id'])){cmsFlash('error','Producto no encontrado.');header('Location:index.php');exit;}}$errores=[];$categorias=$pdo->query('SELECT * FROM categorias_producto WHERE activo=1 ORDER BY nombre')->fetchAll();if($_SERVER['REQUEST_METHOD']==='POST'){$nombre=trim(strip_tags((string)($_POST['nombre']??'')));$sku=trim((string)($_POST['sku']??''));$corta=trim(strip_tags((string)($_POST['descripcion_corta']??'')));$descripcion=trim(strip_tags((string)($_POST['descripcion']??'')));$precio=filter_var($_POST['precio']??null,FILTER_VALIDATE_FLOAT);$stock=filter_var($_POST['stock']??null,FILTER_VALIDATE_INT,['options'=>['min_range'=>0]]);$min=filter_var($_POST['stock_minimo']??null,FILTER_VALIDATE_INT,['options'=>['min_range'=>0]]);$categoria=cmsId($_POST['categoria_id']??0)?:null;$disponible=isset($_POST['disponible'])?1:0;$activo=isset($_POST['activo'])?1:0;if(!validarTokenCsrf($_POST['csrf_token']??null))$errores[]='Token inválido.';if($nombre===''||mb_strlen($nombre)>180)$errores[]='Nombre obligatorio (máximo 180).';if($corta===''||mb_strlen($corta)>500||$descripcion===''||mb_strlen($descripcion)>10000)$errores[]='Completa las descripciones respetando las longitudes.';if($precio===false||$precio<0)$errores[]='Precio inválido.';if($stock===false||$min===false)$errores[]='Stock inválido.';$imagen=$f['imagen_principal'];try{$nueva=cmsSubirImagen('imagen_principal');if($nueva)$imagen=$nueva;$galeria=cmsSubirGaleria('galeria');}catch(RuntimeException$e){$errores[]=$e->getMessage();$galeria=[];}$promoActiva=isset($_POST['promo_activa']);$promoPrecio=filter_var($_POST['precio_promocional']??null,FILTER_VALIDATE_FLOAT);$inicio=str_replace('T',' ',(string)($_POST['promo_inicio']??''));$fin=str_replace('T',' ',(string)($_POST['promo_fin']??''));if($promoActiva&&($promoPrecio===false||$promoPrecio<0||$promoPrecio>=$precio||!strtotime($inicio)||!strtotime($fin)||strtotime($fin)<=strtotime($inicio)))$errores[]='La promoción requiere precio menor y fechas válidas.';if(!$errores){try{$pdo->beginTransaction();$slug=strtolower(trim(preg_replace('/[^a-z0-9]+/','-',iconv('UTF-8','ASCII//TRANSLIT',$nombre)?:$nombre),'-')).'-'.($id?:bin2hex(random_bytes(3)));if($id){$q=$pdo->prepare('UPDATE productos SET categoria_id=:cat,sku=:sku,nombre=:nombre,descripcion_corta=:corta,descripcion=:descripcion,precio=:precio,stock=:stock,stock_minimo=:min,disponible=:disp,activo=:activo,imagen_principal=:imagen,actualizado_por=:admin WHERE id=:id');$q->execute(['cat'=>$categoria,'sku'=>$sku?:null,'nombre'=>$nombre,'corta'=>$corta,'descripcion'=>$descripcion,'precio'=>$precio,'stock'=>$stock,'min'=>$min,'disp'=>$disponible,'activo'=>$activo,'imagen'=>$imagen,'admin'=>$_SESSION['usuario_id'],'id'=>$id]);}else{$q=$pdo->prepare('INSERT INTO productos(categoria_id,sku,nombre,slug,descripcion_corta,descripcion,precio,stock,stock_minimo,disponible,activo,imagen_principal,creado_por,actualizado_por)VALUES(:cat,:sku,:nombre,:slug,:corta,:descripcion,:precio,:stock,:min,:disp,:activo,:imagen,:admin,:admin)');$q->execute(['cat'=>$categoria,'sku'=>$sku?:null,'nombre'=>$nombre,'slug'=>$slug,'corta'=>$corta,'descripcion'=>$descripcion,'precio'=>$precio,'stock'=>$stock,'min'=>$min,'disp'=>$disponible,'activo'=>$activo,'imagen'=>$imagen,'admin'=>$_SESSION['usuario_id']]);$id=(int)$pdo->lastInsertId();}foreach($galeria as$i=>$ruta)$pdo->prepare('INSERT INTO producto_imagenes(producto_id,ruta,orden)VALUES(:p,:r,:o)')->execute(['p'=>$id,'r'=>$ruta,'o'=>$i]);if($promoActiva){$pdo->prepare('UPDATE promociones SET activa=0 WHERE producto_id=:p')->execute(['p'=>$id]);$porcentaje=round((1-$promoPrecio/$precio)*100,2);$pdo->prepare('INSERT INTO promociones(producto_id,etiqueta,precio_promocional,porcentaje_descuento,fecha_inicio,fecha_fin,activa,creado_por,actualizado_por)VALUES(:p,:e,:precio,:porcentaje,:inicio,:fin,1,:admin,:admin)')->execute(['p'=>$id,'e'=>trim(strip_tags((string)($_POST['promo_etiqueta']??'')))?:null,'precio'=>$promoPrecio,'porcentaje'=>$porcentaje,'inicio'=>$inicio,'fin'=>$fin,'admin'=>$_SESSION['usuario_id']]);}else{$pdo->prepare('UPDATE promociones SET activa=0 WHERE producto_id=:p')->execute(['p'=>$id]);}if((int)$f['stock']!==$stock)$pdo->prepare("INSERT INTO inventario_movimientos(producto_id,usuario_admin_id,tipo,cantidad,stock_anterior,stock_nuevo,nota)VALUES(:p,:a,'ajuste',:c,:anterior,:nuevo,'Ajuste desde edición de producto')")->execute(['p'=>$id,'a'=>$_SESSION['usuario_id'],'c'=>$stock-(int)$f['stock'],'anterior'=>(int)$f['stock'],'nuevo'=>$stock]);$pdo->commit();cmsFlash('exito','Producto guardado.');header('Location:index.php');exit;}catch(Throwable$e){if($pdo->inTransaction())$pdo->rollBack();error_log($e->getMessage());$errores[]='No fue posible guardar; verifica SKU y datos.';}}$f=array_merge($f,['nombre'=>$nombre,'sku'=>$sku,'descripcion_corta'=>$corta,'descripcion'=>$descripcion,'precio'=>$precio,'stock'=>$stock,'stock_minimo'=>$min,'disponible'=>$disponible,'activo'=>$activo,'categoria_id'=>$categoria,'imagen_principal'=>$imagen]);}$promo=null;if($id){$q=$pdo->prepare('SELECT * FROM promociones WHERE producto_id=:p ORDER BY id DESC LIMIT 1');$q->execute(['p'=>$id]);$promo=$q->fetch();}$imgs=[];if($id){$q=$pdo->prepare('SELECT * FROM producto_imagenes WHERE producto_id=:p ORDER BY orden,id');$q->execute(['p'=>$id]);$imgs=$q->fetchAll();}cmsCabecera($id?'Editar producto':'Nuevo producto','productos/editar.php');foreach($errores as$e)echo'<div class="alert alert-danger">'.atenea_e($e).'</div>';?><form method="post" enctype="multipart/form-data" class="card card-rounded"><div class="card-body row g-3"><input type="hidden" name="csrf_token" value="<?=atenea_e(obtenerTokenCsrf())?>"><input type="hidden" name="id" value="<?=$id?>"><div class="col-md-8"><label class="form-label">Nombre *</label><input class="form-control" name="nombre" maxlength="180" value="<?=atenea_e($f['nombre'])?>" required></div><div class="col-md-4"><label class="form-label">SKU</label><input class="form-control" name="sku" maxlength="80" value="<?=atenea_e((string)$f['sku'])?>"></div><div class="col-md-6"><label class="form-label">Categoría</label><select class="form-select" name="categoria_id"><option value="">Sin categoría</option><?php foreach($categorias as$c):?><option value="<?=$c['id']?>" <?=$f['categoria_id']==$c['id']?'selected':''?>><?=atenea_e($c['nombre'])?></option><?php endforeach;?></select></div><div class="col-md-6"><label class="form-label">Precio *</label><input class="form-control" type="number" step="0.01" min="0" name="precio" value="<?=$f['precio']?>" required></div><div class="col-12"><label class="form-label">Descripción corta *</label><input class="form-control" name="descripcion_corta" maxlength="500" value="<?=atenea_e($f['descripcion_corta'])?>" required></div><div class="col-12"><label class="form-label">Descripción completa *</label><textarea class="form-control" rows="5" name="descripcion" required><?=atenea_e($f['descripcion'])?></textarea></div><div class="col-md-4"><label class="form-label">Stock</label><input class="form-control" type="number" min="0" name="stock" value="<?=$f['stock']?>"></div><div class="col-md-4"><label class="form-label">Stock mínimo</label><input class="form-control" type="number" min="0" name="stock_minimo" value="<?=$f['stock_minimo']?>"></div><div class="col-md-4 d-flex align-items-end gap-3"><label><input type="checkbox" name="disponible" <?=$f['disponible']?'checked':''?>> Disponible</label><label><input type="checkbox" name="activo" <?=$f['activo']?'checked':''?>> Activo</label></div><div class="col-md-6"><label class="form-label">Imagen principal</label><input class="form-control" type="file" name="imagen_principal" accept=".jpg,.jpeg,.png,.webp"></div><div class="col-md-6"><label class="form-label">Galería</label><input class="form-control" type="file" name="galeria[]" multiple accept=".jpg,.jpeg,.png,.webp"></div><div class="col-12"><hr><h3 class="h5">Promoción</h3></div><div class="col-md-2"><label><input type="checkbox" name="promo_activa" <?=$promo&&$promo['activa']?'checked':''?>> Activa</label></div><div class="col-md-3"><input class="form-control" name="promo_etiqueta" placeholder="Etiqueta" value="<?=atenea_e((string)($promo['etiqueta']??''))?>"></div><div class="col-md-2"><input class="form-control" type="number" step="0.01" name="precio_promocional" placeholder="Precio oferta" value="<?=$promo['precio_promocional']??''?>"></div><div class="col-md-2"><input class="form-control" type="datetime-local" name="promo_inicio" value="<?=$promo?date('Y-m-d\TH:i',strtotime($promo['fecha_inicio'])):''?>"></div><div class="col-md-3"><input class="form-control" type="datetime-local" name="promo_fin" value="<?=$promo?date('Y-m-d\TH:i',strtotime($promo['fecha_fin'])):''?>"></div><?php if($imgs):?><div class="col-12 d-flex gap-2 flex-wrap"><?php foreach($imgs as$im):?><div><img class="preview-img" src="<?=rutaImagenContenido($im['ruta'])?>"><button class="btn btn-sm btn-outline-danger" form="borrar-imagen-<?=$im['id']?>">Eliminar</button></div><?php endforeach;?></div><?php endif;?><div class="col-12"><a class="btn btn-light" href="index.php">Cancelar</a> <button class="btn btn-primary text-white">Guardar</button></div></div></form><?php foreach($imgs as$im):?><form id="borrar-imagen-<?=$im['id']?>" method="post" action="accion.php"><input type="hidden" name="csrf_token" value="<?=atenea_e(obtenerTokenCsrf())?>"><input type="hidden" name="id" value="<?=$im['id']?>"><input type="hidden" name="producto_id" value="<?=$id?>"><input type="hidden" name="accion" value="eliminar_imagen"></form><?php endforeach;?><?php cmsPie();?>
